using System.Diagnostics;

public class Solution {
    public int UniqueLetterString0(string s) {
        List<int[]> substrList = [];
        int res = 0;
        foreach (char c in s)
        {
            substrList.Add(new int[26]);
            foreach (int[] substr in substrList)
            {
                substr[c-'A']++;
                res += UniqueChars(substr);
            }
        }
        return res;
    }

    private static int UniqueChars(int[] a)
    {
        int count = 0;
        for (int i = 0; i < 26; i++)
        {
            if (a[i] == 1)
            {
                count++;
            }
        }
        return count;
    }
    
    public int UniqueLetterString(string s)
    {
        int n = s.Length;
        int res = 0;
        int[,] count = new int[26,2];
        for (int i = 0; i < 26; i++)
        {
            count[i,0] = -1;
            count[i,1] = -1;
        }        

        // count contribution of char from previous occurrence when meeting it again
        for (int i = 0; i < n; i++)
        {
            int c = s[i]-'A';
            res += (i - count[c,1]) * (count[c,1] - count[c,0]);
            (count[c,0], count[c,1]) = (count[c,1], i);
        }

        // count last occurrence for each char
        for (int i = 0; i < 26; i++)
        {
            res += (n - count[i,1]) * (count[i,1] - count[i,0]);
        }
        return res;
    }
}

class Program {
    static void Main(string[] args) {
        Solution sol = new();

        string s = "ABC";
        Debug.Assert(sol.UniqueLetterString(s) == 10);

        s = "ABA";
        Debug.Assert(sol.UniqueLetterString(s) == 8);

        s = "LEETCODE";
        Debug.Assert(sol.UniqueLetterString(s) == 92);

        s = "";
        Debug.Assert(sol.UniqueLetterString(s) == 6600621);

        Console.WriteLine("passed");
    }
}